import{_ as t,o as r,c as o,ag as a}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Trusted setup ceremony","description":"","frontmatter":{},"headers":[],"relativePath":"ceremony/index.md","filePath":"ceremony/README.md","lastUpdated":1777988338000}'),i={name:"ceremony/index.md"};function n(s,e,c,d,u,l){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="trusted-setup-ceremony" tabindex="-1">Trusted setup ceremony <a class="header-anchor" href="#trusted-setup-ceremony" aria-label="Permalink to &quot;Trusted setup ceremony&quot;">​</a></h1><blockquote><p><strong>Renamed 2026-05-03</strong> — see <a href="./2026-05-03-zkqes-rename-design"><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code></a> for the rename baseline. Historical references to QKB/QIE/Identity-Escrow in pre-2026-05-03 commits remain immutable in git history.</p></blockquote><p><code>zkqes</code> uses a Groth16 SNARK; Groth16 requires a structured reference string produced by a multi-party trusted setup. Phase 1 reuses the public Hermez Powers of Tau; Phase 2 is per-circuit and is run as a coordinator-driven multi-contributor chain. So long as one contributor honestly destroys their entropy, the resulting proving key is sound — no contributor needs to trust any other.</p><p>This page is the developer-side reference. The contributor-facing coordination surface — round-by-round chain, attestation log, paste-attestation verifier, recruitment paths — lives on the project landing at <a href="https://zkqes.org/ceremony" target="_blank" rel="noreferrer"><code>zkqes.org/ceremony</code></a>.</p><h2 id="phase-1-—-universal" tabindex="-1">Phase 1 — universal <a class="header-anchor" href="#phase-1-—-universal" aria-label="Permalink to &quot;Phase 1 — universal&quot;">​</a></h2><p><code>powersOfTau28_hez_final_22.ptau</code> (Hermez Phase 1, 2²² = 4.19M-constraint cap). SHA-256 pinned in <code>packages/circuits/ceremony/scripts/setup.sh</code>. Already public, already audited; no new Phase 1 is required.</p><h2 id="phase-2-—-per-circuit-multi-contributor" tabindex="-1">Phase 2 — per-circuit, multi-contributor <a class="header-anchor" href="#phase-2-—-per-circuit-multi-contributor" aria-label="Permalink to &quot;Phase 2 — per-circuit, multi-contributor&quot;">​</a></h2><p>The Phase B ceremony runs 5-10 contributors against the V5.2 / V5.3 circuit. Each contributor:</p><ol><li>Downloads the previous round&#39;s intermediate <code>.zkey</code> from the coordinator. Artifacts are R2-backed under <code>prove.zkqes.org/ceremony/</code>.</li><li>Runs <code>snarkjs zkey contribute</code> locally with their own entropy. Roughly twenty minutes wall time on a 32 GB-RAM machine; approximately 30 GB peak memory.</li><li>Verifies the output locally before uploading.</li><li>Uploads via a single-use signed URL issued by the coordinator.</li></ol><p>A public beacon — a future Ethereum block hash — is applied as the final entropy injection after the last contributor lands. The beacon binds the final <code>.zkey</code> to a public timestamp that no participant could grind.</p><h2 id="attestation-chain" tabindex="-1">Attestation chain <a class="header-anchor" href="#attestation-chain" aria-label="Permalink to &quot;Attestation chain&quot;">​</a></h2><p>Every round publishes a contributor handle, an attestation hash, and the image digest of the build environment used to run the contribution. The chain is consumed live by <code>zkqes.org/ceremony</code> and is independently verifiable via <code>snarkjs zkey verify</code> against the previous round&#39;s <code>.zkey</code>. The full transcript lives at <code>packages/circuits/ceremony/contributions/</code>.</p><h2 id="production-deployment" tabindex="-1">Production deployment <a class="header-anchor" href="#production-deployment" aria-label="Permalink to &quot;Production deployment&quot;">​</a></h2><p>A Phase B ceremony output is the prerequisite for any production-qualified deployment. The flow:</p><ol><li>Final round and beacon land.</li><li>The auto-generated Solidity verifier (<code>Groth16VerifierV5_*.sol</code>) replaces the in-tree stub at <code>packages/contracts/src/</code>.</li><li>Contracts redeploy on Base Sepolia — and, post-audit, on Base mainnet — with the real verifier address pumped to <code>fixtures/contracts/&lt;network&gt;.json</code>.</li><li>The frontend phase flips from <code>ceremony-live</code> to <code>live</code>; the registry switches from the stub verifier to the real one.</li></ol><p>See the <a href="/specs/v5-architecture">V5 architecture spec</a> §11 for the full Phase 2 contract.</p><h2 id="contributing-a-round" tabindex="-1">Contributing a round <a class="header-anchor" href="#contributing-a-round" aria-label="Permalink to &quot;Contributing a round&quot;">​</a></h2><p>Recruitment is coordinator-driven. If you maintain ZK infrastructure — PSE, 0xPARC, Mopro, Anon Aadhaar, Polygon ID, or a research lab in the same lineage — and would like to attest a round, reach out via the project&#39;s social channels. The four-command contributor flow plus the hardware requirements are documented at <a href="https://zkqes.org/ceremony/contribute" target="_blank" rel="noreferrer"><code>zkqes.org/ceremony/contribute</code></a>.</p>',18)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
